### 6.2 CourseRepository Update

```typescript
// src/infrastructure/repositories/course.repository.ts

async findByIds(ids: mongoose.Types.ObjectId[], options: PaginationOptions) {
  const { page, limit } = options;
  const skip = (page - 1) * limit;

  const [data, total] = await Promise.all([
    this.model.find({ _id: { $in: ids } })
      .populate('license_category_id', 'name code')
      .sort({ created_at: -1 })
      .skip(skip)
      .limit(limit)
      .lean(),
    this.model.countDocuments({ _id: { $in: ids } })
  ]);

  return {
    data,
    meta: {
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit)
    }
  };
}
```

