```typescript
// src/application/services/data-isolation.helper.ts

import mongoose from 'mongoose';
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { UserRole } from '@/infrastructure/database/models/user.model';

export interface AuthUser {
  id: string;
  _id: mongoose.Types.ObjectId;
  role: UserRole;
}

export class DataIsolationHelper {

  /**
   * Lấy danh sách student_ids mà teacher được phân công
   */
  static async getAssignedStudentIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('student_id');

    return courseStudents;
  }

  /**
   * Lấy danh sách course_ids mà teacher được phân công
   */
  static async getAssignedCourseIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('course_id');

    return courseStudents;
  }

  /**
   * Lấy danh sách course_student_ids mà teacher được phân công
   */
  static async getAssignedCourseStudentIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('_id');

    return courseStudents;
  }

  /**
   * Kiểm tra xem student có thuộc quyền quản lý của teacher không
   */
  static async isStudentAssignedToTeacher(
    studentId: string | mongoose.Types.ObjectId,
    teacherId: string | mongoose.Types.ObjectId
  ): Promise<boolean> {
    const count = await CourseStudentModel.countDocuments({
      student_id: studentId,
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    });
    return count > 0;
  }

