import mongoose from 'mongoose';
import { CourseStudentModel, ICourseStudent, CourseStudentStatus } from '@/infrastructure/database/models/course_student.model';
import { PaymentModel } from '@/infrastructure/database/models/payment.model';
import { DatSessionModel } from '@/infrastructure/database/models/dat_session.model';
import logger from '@/infrastructure/logging/logger';
import { AppError } from '@/domain/exceptions/app-error';

/**
 * Cancel preview data structure
 */
export interface CancelPreview {
  hasPayments: boolean;
  hasDatSessions: boolean;
  datCompleted: boolean;
  warnings: string[];
  paymentCount: number;
  totalDatKm: number;
}

/**
 * CourseStudent Service
 * Handles enrollment-related business logic including soft delete (cancellation)
 */
export class CourseStudentService {
  /**
   * Get enrollment by ID with optional active-only filter
   */
  async getEnrollmentById(id: string, activeOnly = false): Promise<ICourseStudent | null> {
    const filter: any = { _id: new mongoose.Types.ObjectId(id) };
    if (activeOnly) {
      filter.status = { $ne: 'canceled' };
    }
    return await CourseStudentModel.findOne(filter);
  }

  /**
   * Cancel an enrollment (Soft Delete)
   * - Sets status to 'canceled'
   * - Records canceled_at, cancel_reason, canceled_by
   * - Does NOT delete any related records (payments, dat sessions, etc.)
   */
  async cancelEnrollment(id: string, reason: string, userId: string): Promise<ICourseStudent> {
    // 1. Find the enrollment
    const enrollment = await CourseStudentModel.findById(id);
    if (!enrollment) {
      throw new AppError('Enrollment not found', 404);
    }

    // 2. Check if already canceled
    if (enrollment.status === 'canceled') {
      throw new AppError('Enrollment đã bị hủy trước đó', 400);
    }

    // 3. Update enrollment with cancellation data
    enrollment.status = 'canceled';
    enrollment.canceled_at = new Date();
    enrollment.cancel_reason = reason;
    enrollment.canceled_by = new mongoose.Types.ObjectId(userId);

    const savedEnrollment = await enrollment.save();

    logger.info('Enrollment canceled successfully', {
      enrollmentId: id,
      reason,
      canceledBy: userId,
      studentId: enrollment.student_id,
      courseId: enrollment.course_id,
    });

    return savedEnrollment;
  }

  /**
   * Get cancel preview - check for payments and DAT sessions before cancel
   * Used by frontend to show warning dialogs before confirming cancellation
   */
  async getCancelPreview(id: string): Promise<CancelPreview> {
    // 1. Find the enrollment
    const enrollment = await CourseStudentModel.findById(id);
    if (!enrollment) {
      throw new AppError('Enrollment not found', 404);
    }

    // 2. Check if already canceled
    if (enrollment.status === 'canceled') {
      throw new AppError('Enrollment đã bị hủy trước đó', 400);
    }

    // 3. Parallel queries for payments and DAT sessions
    const enrollmentOid = new mongoose.Types.ObjectId(id);

    const [paymentCount, datSessionCount, totalDatKmResult] = await Promise.all([
      PaymentModel.countDocuments({ course_student_id: id }),
      DatSessionModel.countDocuments({ course_student_id: id }),
      DatSessionModel.aggregate([
        { $match: { course_student_id: enrollmentOid } },
        { $group: { _id: null, totalKm: { $sum: '$distance_km' } } },
      ]),
    ]);

    const totalKm = totalDatKmResult[0]?.totalKm || 0;
    const hasPayments = paymentCount > 0;
    const hasDatSessions = datSessionCount > 0;
    const datCompleted = totalKm >= 810; // DAT threshold is 810km

    // Build warnings based on findings
    const warnings: string[] = [];

    if (hasPayments) {
      warnings.push(`Đã có ${paymentCount} khoản thanh toán — sẽ được giữ lại trong lịch sử`);
    }

    if (datCompleted) {
      warnings.push(`Đã hoàn thành DAT (${totalKm}km) — tiến độ sẽ được giữ trong lịch sử`);
    }

    return {
      hasPayments,
      hasDatSessions,
      datCompleted,
      warnings,
      paymentCount,
      totalDatKm: totalKm,
    };
  }

  /**
   * Get enrollment history for a student
   * Returns active enrollment and historical (canceled/completed) enrollments
   */
  async getStudentEnrollmentHistory(studentId: string): Promise<{ active: ICourseStudent | null; history: ICourseStudent[] }> {
    const enrollments = await CourseStudentModel.find({ student_id: studentId })
      .sort({ created_at: -1 })
      .populate('course_id', 'name code');

    const active = enrollments.find((e) => e.status !== 'canceled') || null;
    const history = enrollments.filter((e) => e.status === 'canceled');

    return { active, history };
  }

  /**
   * Get all active enrollments (excludes canceled)
   * Used for queries that need only active enrollments
   */
  async getActiveEnrollments(filters = {}, page = 1, limit = 20): Promise<{ data: ICourseStudent[]; total: number }> {
    const query = { ...filters, status: { $ne: 'canceled' } };
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      CourseStudentModel.find(query)
        .sort({ created_at: -1 })
        .skip(skip)
        .limit(limit)
        .populate('student_id', 'user_id license_category_id')
        .populate('course_id', 'name code'),
      CourseStudentModel.countDocuments(query),
    ]);

    return { data, total };
  }

  /**
   * Check if student can be enrolled in a new course
   * Returns true if no active enrollment exists
   */
  async canEnrollNewCourse(studentId: string, excludeEnrollmentId?: string): Promise<boolean> {
    const filter: any = { student_id: studentId, status: { $ne: 'canceled' } };
    if (excludeEnrollmentId) {
      filter._id = { $ne: new mongoose.Types.ObjectId(excludeEnrollmentId) };
    }
    const activeCount = await CourseStudentModel.countDocuments(filter);
    return activeCount === 0;
  }
}

// Export singleton instance
export const courseStudentService = new CourseStudentService();

