  it('allows empty reason string', async () => {
    const enrollment = makeMockEnrollment('studying');
    mockEnrollmentSave.mockResolvedValue({ ...enrollment, status: 'canceled' });
    mockCourseStudentFindById.mockResolvedValue(enrollment);

    const result = await service.cancelEnrollment(mockEnrollmentId, '', mockUserId);

    expect(result.status).toBe('canceled');
  });
});

describe('getCancelPreview', () => {
  it('throws NotFoundException when enrollment does not exist', async () => {
    mockCourseStudentFindById.mockResolvedValue(null);
    await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(AppError);
  });

  it('throws BadRequestException when already canceled', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('canceled'));
    await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(AppError);
  });

  it('returns empty warnings when no payments or DAT sessions', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(0);
    mockDatSessionCountDocuments.mockResolvedValue(0);
    mockDatSessionAggregate.mockResolvedValue([]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.hasPayments).toBe(false);
    expect(result.hasDatSessions).toBe(false);
    expect(result.warnings).toEqual([]);
  });

  it('returns warning when payments exist', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(2);
    mockDatSessionCountDocuments.mockResolvedValue(0);
    mockDatSessionAggregate.mockResolvedValue([]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.hasPayments).toBe(true);
    expect(result.warnings).toContain('Đã có 2 khoản thanh toán — sẽ được giữ lại trong lịch sử');
  });

  it('marks DAT completed when km >= 810', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(0);
    mockDatSessionCountDocuments.mockResolvedValue(5);
    mockDatSessionAggregate.mockResolvedValue([{ _id: null, totalKm: 850 }]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.datCompleted).toBe(true);
    expect(result.warnings).toContain('Đã hoàn thành DAT (850km) — tiến độ sẽ được giữ trong lịch sử');
  });

  it('does not mark DAT completed when km < 810', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(0);
    mockDatSessionCountDocuments.mockResolvedValue(5);
    mockDatSessionAggregate.mockResolvedValue([{ _id: null, totalKm: 500 }]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.datCompleted).toBe(false);
    expect(result.warnings).toEqual([]);
  });

  it('returns multiple warnings for both payments and completed DAT', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(3);
    mockDatSessionCountDocuments.mockResolvedValue(10);
    mockDatSessionAggregate.mockResolvedValue([{ _id: null, totalKm: 900 }]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.warnings.length).toBe(2);
    expect(result.warnings).toContain('Đã có 3 khoản thanh toán — sẽ được giữ lại trong lịch sử');
    expect(result.warnings).toContain('Đã hoàn thành DAT (900km) — tiến độ sẽ được giữ trong lịch sử');
  });

  it('handles empty aggregate result', async () => {
    mockCourseStudentFindById.mockResolvedValue(makeMockEnrollment('studying'));
    mockPaymentCountDocuments.mockResolvedValue(0);
    mockDatSessionCountDocuments.mockResolvedValue(0);
    mockDatSessionAggregate.mockResolvedValue([]);

    const result = await service.getCancelPreview(mockEnrollmentId);

    expect(result.totalDatKm).toBe(0);
    expect(result.datCompleted).toBe(false);
  });
});

describe('getEnrollmentById', () => {
  it('returns enrollment with activeOnly=false', async () => {
    const enrollment = { _id: new mongoose.Types.ObjectId(mockEnrollmentId), status: 'studying' };
    mockCourseStudentFindOne.mockResolvedValue(enrollment);
    const result = await service.getEnrollmentById(mockEnrollmentId, false);
    expect(result).toEqual(enrollment);
  });

  it('filters out canceled enrollments with activeOnly=true', async () => {
    mockCourseStudentFindOne.mockResolvedValue(null);
    await service.getEnrollmentById(mockEnrollmentId, true);
    expect(mockCourseStudentFindOne).toHaveBeenCalledWith(
      expect.objectContaining({ status: { $ne: 'canceled' } })
    );
  });

  it('returns null when not found', async () => {
    mockCourseStudentFindOne.mockResolvedValue(null);
    const result = await service.getEnrollmentById(mockEnrollmentId);
    expect(result).toBeNull();
  });
});

describe('canEnrollNewCourse', () => {
  const mockStudentId = '507f1f77bcf86cd799439013';

  it('returns true when no active enrollments', async () => {
    mockCourseStudentCountDocuments.mockResolvedValue(0);
    const result = await service.canEnrollNewCourse(mockStudentId);
    expect(result).toBe(true);
  });

  it('returns false when active enrollments exist', async () => {
    mockCourseStudentCountDocuments.mockResolvedValue(1);
    const result = await service.canEnrollNewCourse(mockStudentId);
    expect(result).toBe(false);
  });

  it('excludes specific enrollment when excludeEnrollmentId provided', async () => {
    const excludeId = '507f1f77bcf86cd799439014';
    mockCourseStudentCountDocuments.mockResolvedValue(0);
    await service.canEnrollNewCourse(mockStudentId, excludeId);
    expect(mockCourseStudentCountDocuments).toHaveBeenCalledWith(
      expect.objectContaining({
        _id: { $ne: expect.any(mongoose.Types.ObjectId) },
      })
    );
  });
});

